import React, { useEffect, useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Trash2, X, Save, Calendar, ArrowUpRight, ShoppingCart 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [compras, setCompras] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedCartao, setSelectedCartao] = useState(null);
  const [loading, setLoading] = useState(true);
  
  const [novoCartao, setNovoCartao] = useState({
    nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1'
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  const fecharModais = useCallback(() => {
    setShowModal(false);
    setSelectedCartao(null);
  }, []);

  // Fechar com ESC
  useEffect(() => {
    const handleEsc = (event) => {
      if (event.key === 'Escape') fecharModais();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [fecharModais]);

  useEffect(() => {
    fetchDados();
  }, []);

  async function fetchDados() {
    setLoading(true);
    const { data: cData } = await supabase.from('cartoes').select('*').order('nome');
    const { data: compData } = await supabase.from('compras').select('*');
    setCartoes(cData || []);
    setCompras(compData || []);
    setLoading(false);
  }

  // Lógica de Limite Disponível (Consome o valor TOTAL da compra enquanto houver parcelas pendentes)
  const calcularDisponivel = (cartaoNome, limite) => {
    const totalComprometido = compras.reduce((acc, item) => {
      if (item.cartao !== cartaoNome) return acc;

      const dataCompra = new Date(item.data_compra);
      const numParcelas = item.num_parcelas || 1;
      
      const dataUltimaParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + (numParcelas - 1), 1);
      const dataFiltroAtual = new Date(anoAtual, mesAtual, 1);

      if (dataUltimaParcela >= dataFiltroAtual) {
        return acc + parseFloat(item.valor_total);
      }
      return acc;
    }, 0);

    return limite - totalComprometido;
  };

  // Lógica para o Total da Fatura (Soma apenas o que cai no mês atual)
  const calcularTotalMes = (cartaoNome) => {
    return compras.reduce((acc, item) => {
      if (item.cartao !== cartaoNome) return acc;
      
      const numParcelas = item.num_parcelas || 1;
      let valorNoMes = 0;

      for (let i = 0; i < numParcelas; i++) {
        const dC = new Date(item.data_compra);
        const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
        if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
          valorNoMes = parseFloat(item.valor_total) / numParcelas;
        }
      }
      return acc + valorNoMes;
    }, 0);
  };

  async function handleSave(e) {
    e.preventDefault();
    const { error } = await supabase.from('cartoes').insert([{ 
      ...novoCartao, 
      limite: parseFloat(novoCartao.limite),
      dia_fechamento: parseInt(novoCartao.dia_fechamento) || 1,
      dia_vencimento: parseInt(novoCartao.dia_vencimento) || 1
    }]);
    if (!error) {
      fecharModais();
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1' });
      fetchDados();
    }
  }

  const formatMoney = (v) => `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ paddingBottom: '40px' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '2rem', fontWeight: '800' }}>Minha Carteira</h1>
          <p style={{ color: 'var(--text-muted)' }}>Gerencie seus limites reais e gastos mensais.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowModal(true)} style={{ borderRadius: '14px' }}>
          <Plus size={20} /> Novo Cartão
        </button>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(340px, 1fr))', gap: '30px' }}>
        {cartoes.map(cartao => {
          const disponivel = calcularDisponivel(cartao.nome, cartao.limite);
          const perc = Math.max(0, (disponivel / cartao.limite) * 100);

          return (
            <div key={cartao.id} className="card-cartao" 
              onClick={() => setSelectedCartao(cartao)}
              style={{ 
                background: `linear-gradient(135deg, ${cartao.cor}, #0f172a)`, 
                color: 'white', padding: '32px', borderRadius: '24px', cursor: 'pointer',
                minHeight: '220px', display: 'flex', flexDirection: 'column', justifyContent: 'space-between',
                boxShadow: `0 20px 25px -5px ${cartao.cor}44`, position: 'relative', overflow: 'hidden',
                transition: 'transform 0.2s'
              }}>
              
              <div style={{ display: 'flex', justifyContent: 'space-between', zIndex: 1 }}>
                <div>
                   <span style={{ fontSize: '0.7rem', fontWeight: '700', opacity: 0.8, textTransform: 'uppercase' }}>Crédito</span>
                   <div style={{ fontWeight: 800, fontSize: '1.5rem', letterSpacing: '-0.5px' }}>{cartao.nome}</div>
                </div>
                <CreditCard size={32} opacity={0.5} />
              </div>
              
              <div style={{ zIndex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '10px' }}>
                   <div>
                      <small style={{ opacity: 0.8, fontSize: '0.65rem', fontWeight: '700' }}>LIMITE DISPONÍVEL</small>
                      <div style={{ fontSize: '1.7rem', fontWeight: 800 }}>{formatMoney(disponivel)}</div>
                   </div>
                   <div style={{ fontSize: '0.85rem', fontWeight: '700', background: 'rgba(255,255,255,0.2)', padding: '2px 8px', borderRadius: '6px' }}>
                     {Math.round(perc)}%
                   </div>
                </div>
                <div style={{ background: 'rgba(255,255,255,0.15)', height: '8px', borderRadius: '12px', overflow: 'hidden' }}>
                  <div style={{ background: 'white', height: '100%', width: `${perc}%`, transition: 'width 1s cubic-bezier(0.4, 0, 0.2, 1)' }} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL DE COMPRAS - TOTALIZADOR NO RODAPÉ */}
      {selectedCartao && (
        <div className="modal-overlay" onClick={fecharModais} style={{ backdropFilter: 'blur(8px)', zIndex: 1000 }}>
          <div className="modal-content fade-in" onClick={e => e.stopPropagation()} 
            style={{ maxWidth: '500px', width: '95%', borderRadius: '28px', padding: '0', overflow: 'hidden', border: 'none' }}>
            
            {/* Header */}
            <div style={{ background: selectedCartao.cor, padding: '30px', color: 'white' }}>
               <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '800' }}>{selectedCartao.nome}</h2>
                  <div onClick={fecharModais} style={{ cursor: 'pointer', background: 'rgba(0,0,0,0.2)', padding: '5px', borderRadius: '50%', display: 'flex' }}>
                    <X size={20} />
                  </div>
               </div>
               <div style={{ marginTop: '12px', fontSize: '0.9rem', opacity: 0.9, fontWeight: '500' }}>
                 Limite Total: {formatMoney(selectedCartao.limite)}
               </div>
            </div>

            {/* Listagem */}
            <div style={{ padding: '25px', background: 'white' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '20px', color: '#64748b' }}>
                <ShoppingCart size={16} />
                <h4 style={{ margin: 0, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Lançamentos do Mês</h4>
              </div>

              <div style={{ maxHeight: '300px', overflowY: 'auto', paddingRight: '5px' }}>
                {compras
                  .filter(c => c.cartao === selectedCartao.nome)
                  .map((item, idx) => {
                    const numParcelas = item.num_parcelas || 1;
                    let infoMês = null;

                    for (let i = 0; i < numParcelas; i++) {
                      const dC = new Date(item.data_compra);
                      const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
                      if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
                        infoMês = { atual: i + 1, total: numParcelas, valor: parseFloat(item.valor_total) / numParcelas };
                      }
                    }

                    if (!infoMês) return null;

                    return (
                      <div key={idx} style={{ 
                        display: 'flex', justifyContent: 'space-between', padding: '14px', 
                        borderRadius: '16px', background: '#f8fafc', marginBottom: '10px', 
                        border: '1px solid #f1f5f9', alignItems: 'center' 
                      }}>
                        <div>
                          <div style={{ fontWeight: '700', color: '#1e293b', fontSize: '0.95rem' }}>{item.descricao}</div>
                          <div style={{ fontSize: '0.75rem', color: '#64748b', marginTop: '2px' }}>
                            {item.parcelado ? `Parcela ${infoMês.atual}/${infoMês.total}` : 'Pagamento à Vista'}
                          </div>
                        </div>
                        <div style={{ fontWeight: '800', color: '#0f172a' }}>{formatMoney(infoMês.valor)}</div>
                      </div>
                    );
                  })}
              </div>

              {/* RODAPÉ COM TOTAL DO MÊS */}
              <div style={{ 
                marginTop: '20px', padding: '20px', borderRadius: '20px', 
                background: '#f1f5f9', border: '1px dashed #cbd5e1',
                display: 'flex', justifyContent: 'space-between', alignItems: 'center'
              }}>
                <div>
                  <span style={{ fontSize: '0.75rem', fontWeight: '700', color: '#64748b', display: 'block' }}>TOTAL DA FATURA</span>
                  <span style={{ fontSize: '0.8rem', color: '#94a3b8' }}>Vencimento dia {selectedCartao.dia_vencimento}</span>
                </div>
                <div style={{ fontSize: '1.4rem', fontWeight: '900', color: selectedCartao.cor }}>
                  {formatMoney(calcularTotalMes(selectedCartao.nome))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE CADASTRO */}
      {showModal && (
        <div className="modal-overlay" onClick={fecharModais} style={{ backdropFilter: 'blur(8px)' }}>
          <div className="modal-content fade-in" onClick={e => e.stopPropagation()} style={{ borderRadius: '24px', padding: '30px', maxWidth: '450px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
               <h3 style={{ margin: 0, fontWeight: '800' }}>Novo Cartão</h3>
               <X style={{ cursor: 'pointer' }} onClick={fecharModais} />
            </div>
            <form onSubmit={handleSave} style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
               <div>
                 <label style={{ fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' }}>NOME DO BANCO</label>
                 <input className="form-control" placeholder="Ex: Nubank" required onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})} />
               </div>
               <div>
                 <label style={{ fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' }}>LIMITE TOTAL</label>
                 <input className="form-control" type="number" placeholder="R$ 0,00" required onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})} />
               </div>
               <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                 <div>
                    <label style={{ fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' }}>FECHAMENTO</label>
                    <input className="form-control" type="number" placeholder="Dia" onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})} />
                 </div>
                 <div>
                    <label style={{ fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' }}>VENCIMENTO</label>
                    <input className="form-control" type="number" placeholder="Dia" onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})} />
                 </div>
               </div>
               <div>
                 <label style={{ fontSize: '0.7rem', fontWeight: '800', color: '#64748b', marginBottom: '5px', display: 'block' }}>COR DO CARD</label>
                 <input type="color" className="form-control" value={novoCartao.cor} onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})} style={{ height: '45px', padding: '4px' }} />
               </div>
               <button type="submit" className="btn-primary" style={{ height: '50px', borderRadius: '14px', marginTop: '10px' }}>Salvar Cartão</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cartoes;
